### 3. `viz/lib/hooks/useInferenceStream.ts`

Mirrors CardDealer `useAgentStream.ts` exactly:

```typescript
'use client'
import { useEffect, useRef, useState } from 'react'

const API = `http://127.0.0.1:${process.env.NEXT_PUBLIC_INFERENCE_PORT ?? '5050'}`

export type InferenceEvent =
  | { type: 'unmask';      block_idx: number; step_idx: number; position: number; token_id: number; confidence: number; entropy: number }
  | { type: 'block_step';  block_idx: number; step_idx: number; n_total_masked: number; n_unmasked_now: number; token_sequence: number[] }
  | { type: 'logit_capture'; block_idx: number; step_idx: number; positions: number[]; top_k_ids: number[][]; top_k_probs: number[][] }
  | { type: 'done';        session_id: string }

export function useInferenceStream(sessionId: string | null) {
  const [events, setEvents]     = useState<InferenceEvent[]>([])
  const [connected, setConnected] = useState(false)
  const esRef      = useRef<EventSource | null>(null)
  const retryDelay = useRef(1000)
  const retryTimer = useRef<ReturnType<typeof setTimeout> | null>(null)
  const unmounted  = useRef(false)

  useEffect(() => {
    if (!sessionId) return
    unmounted.current = false

    function connect() {
      if (unmounted.current) return
      const es = new EventSource(`${API}/api/session/${sessionId}/stream`)
      esRef.current = es
      es.onopen = () => { retryDelay.current = 1000; setConnected(true) }
      es.onerror = () => {
        setConnected(false); es.close(); esRef.current = null
        if (!unmounted.current)
          retryTimer.current = setTimeout(() => {
            retryDelay.current = Math.min(retryDelay.current * 2, 30_000)
            connect()
          }, retryDelay.current)
      }
      es.onmessage = (e) => {
        try {
          const ev = JSON.parse(e.data) as InferenceEvent
          setEvents(prev => [...prev, ev].slice(-5000))
        } catch {}
      }
    }
    connect()
    return () => {
      unmounted.current = true
      if (retryTimer.current) clearTimeout(retryTimer.current)
      esRef.current?.close(); esRef.current = null; setConnected(false)
    }
  }, [sessionId])

  return { events, connected }
}
```

### 4. `viz/components/TokenGrid.tsx`

```typescript
'use client'
import React from 'react'

const MASK_ID = -1

function confColor(conf: number): string {
  if (conf <= 0) return '#374151'  // masked — gray-700
  const r = Math.round(239 - conf * (239 - 34))   // ef4444 → 22c55e
  const g = Math.round(68  + conf * (197 - 68))
  const b = Math.round(68  + conf * (94  - 68))
  return `rgb(${r},${g},${b})`
}

interface Props {
  tokens:      number[]
  confidences: number[]   // per-position, 0 if masked
  onSelect?:   (pos: number) => void
}

export default function TokenGrid({ tokens, confidences, onSelect }: Props) {
  return (
    <div className="flex flex-wrap gap-1 font-mono text-xs">
      {tokens.map((tid, pos) => (
        <button
          key={pos}
          onClick={() => onSelect?.(pos)}
          title={`pos=${pos} tok=${tid} conf=${confidences[pos]?.toFixed(3)}`}
          style={{ background: confColor(confidences[pos] ?? 0) }}
          className="px-1.5 py-0.5 rounded text-white transition-all duration-300"
        >
          {tid === MASK_ID ? '░' : String(tid).slice(0, 4)}
        </button>
      ))}
    </div>
  )
}
```

### 5. `viz/components/BlockStepper.tsx`

```typescript
'use client'
import React, { useState, useEffect, useRef } from 'react'

interface Step {
  block_idx: number; step_idx: number
  token_sequence: number[]; n_total_masked: number; n_unmasked_now: number
}
interface Props { steps: Step[]; onStep: (s: Step) => void }

export default function BlockStepper({ steps, onStep }: Props) {
  const [cursor, setCursor] = useState(0)
  const [playing, setPlaying] = useState(false)
  const timer = useRef<ReturnType<typeof setInterval> | null>(null)

  useEffect(() => {
    if (steps[cursor]) onStep(steps[cursor])
  }, [cursor, steps])

  useEffect(() => {
    if (playing) {
      timer.current = setInterval(() => setCursor(c => Math.min(c + 1, steps.length - 1)), 300)
    } else if (timer.current) clearInterval(timer.current)
    return () => { if (timer.current) clearInterval(timer.current) }
  }, [playing, steps.length])

  return (
    <div className="flex items-center gap-2 text-sm">
      <button onClick={() => setCursor(0)}>⏮</button>
      <button onClick={() => setCursor(c => Math.max(0, c - 1))}>◀</button>
      <button onClick={() => setPlaying(p => !p)}>{playing ? '⏸' : '▶'}</button>
      <button onClick={() => setCursor(c => Math.min(c + 1, steps.length - 1))}>▶▶</button>
      <button onClick={() => setCursor(steps.length - 1)}>⏭</button>
      <span className="ml-2 text-gray-400">step {cursor + 1} / {steps.length}</span>
    </div>
  )
}
```

