### 9. `viz/app/page.tsx` — Landing / Run Config

```typescript
'use client'
import { useState } from 'react'
import { useRouter } from 'next/navigation'
const API = `http://127.0.0.1:${process.env.NEXT_PUBLIC_INFERENCE_PORT ?? '5050'}`

export default function HomePage() {
  const router = useRouter()
  const [mode, setMode] = useState('mock')
  const [genLen, setGenLen] = useState(128)
  const [loading, setLoading] = useState(false)

  async function start() {
    setLoading(true)
    const res = await fetch(`${API}/api/sessions`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ mode, params: { gen_length: genLen } }),
    })
    const { session_id } = await res.json()
    router.push(`/session/${session_id}`)
  }

  return (
    <main className="max-w-lg mx-auto mt-20 p-6 bg-gray-900 rounded-xl space-y-4">
      <h1 className="text-2xl font-bold">Fast-dLLM Inference Visualizer</h1>
      <label className="block">
        <span className="text-sm text-gray-400">Mode</span>
        <select value={mode} onChange={e => setMode(e.target.value)}
          className="mt-1 block w-full bg-gray-800 rounded px-3 py-2">
          <option value="mock">Mock (no GPU)</option>
          <option value="v1">v1 — LLaDA</option>
          <option value="v2">v2 — Qwen</option>
        </select>
      </label>
      <label className="block">
        <span className="text-sm text-gray-400">Generation length</span>
        <input type="number" value={genLen} onChange={e => setGenLen(+e.target.value)}
          className="mt-1 block w-full bg-gray-800 rounded px-3 py-2" />
      </label>
      <button onClick={start} disabled={loading}
        className="w-full bg-blue-600 hover:bg-blue-500 py-2 rounded font-semibold">
        {loading ? 'Starting…' : 'Start Generation'}
      </button>
    </main>
  )
}
```

### 10. `viz/app/session/[id]/page.tsx` — Live Visualization

```typescript
'use client'
import { useState } from 'react'
import { useParams } from 'next/navigation'
import { useInferenceStream, InferenceEvent } from '@/lib/hooks/useInferenceStream'
import TokenGrid from '@/components/TokenGrid'
import BlockStepper from '@/components/BlockStepper'
import ConnectionBadge from '@/components/ConnectionBadge'

type Snap = { block_idx: number; step_idx: number; token_sequence: number[];
              n_total_masked: number; n_unmasked_now: number }

export default function SessionPage() {
  const { id } = useParams<{ id: string }>()
  const { events, connected } = useInferenceStream(id)
  const [current, setCurrent] = useState<Snap | null>(null)
  const [confidences, setConfidences] = useState<number[]>([])

  // Collect block step snapshots for stepper
  const steps = events
    .filter((e): e is Extract<InferenceEvent, { type: 'block_step' }> => e.type === 'block_step')

  // Update confidences from unmask events
  const latestConf: number[] = []
  events.filter(e => e.type === 'unmask').forEach(e => {
    const ev = e as Extract<InferenceEvent, { type: 'unmask' }>
    latestConf[ev.position] = ev.confidence
  })

  return (
    <main className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-bold">Session: {id}</h1>
        <ConnectionBadge connected={connected} />
      </div>

      {current && (
        <section>
          <p className="text-sm text-gray-400 mb-2">
            Block {current.block_idx} · Step {current.step_idx} ·
            {current.n_total_masked} masked · {current.n_unmasked_now} unmasked this step
          </p>
          <TokenGrid tokens={current.token_sequence}
                     confidences={latestConf}
                     onSelect={pos => console.log('clicked pos', pos)} />
        </section>
      )}

      {steps.length > 0 && (
        <BlockStepper steps={steps} onStep={s => { setCurrent(s); setConfidences(latestConf) }} />
      )}

      <p className="text-xs text-gray-500">{events.length} events received</p>
    </main>
  )
}
```

